import{_ as a,o as r,c as o,a3 as t}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"4. Coverage","description":"","frontmatter":{"title":"4. Coverage","eba":"Medical Specialists 2022-2026","topics":["preliminary"]},"headers":[],"relativePath":"ebas/medical-specialists/preliminary/4-coverage.md","filePath":"ebas/medical-specialists/preliminary/4-coverage.md"}'),s={name:"ebas/medical-specialists/preliminary/4-coverage.md"};function i(n,e,c,l,p,d){return r(),o("div",null,[...e[0]||(e[0]=[t('<h1 id="_4-coverage" tabindex="-1">4. Coverage <a class="header-anchor" href="#_4-coverage" aria-label="Permalink to &quot;4. Coverage&quot;">​</a></h1><p><strong>4.1</strong> Subject to subclause 4.2, this Agreement covers:</p><p><strong>(a)</strong> the Health Services (referred to in <a href="/eba/ebas/doctors-in-training/appendices/1-list-of-employers-health-services.html">Appendix 1</a>) as employers;</p><p><strong>(b)</strong> all Doctors (as defined in subclause 3.1(k)) as Doctors; and</p><p>provided the FWC so notes in its decision to approve this Agreement:</p><p><strong>(c)</strong> the Australian Salaried Medical Officers’ Federation.</p><p><strong>4.2</strong> For the avoidance of any doubt, this Agreement does not cover any person in relation to ordinary work performed wholly on a fee for service or scheduled fee basis (including, by way of example only, the Commonwealth Medical Benefits Schedule (CMBS)).</p><p>Plain language terms: scope, who is covered.</p>',8)])])}const h=a(s,[["render",i]]);export{m as __pageData,h as default};
